### IaC File Format
```json
{
  "channels": [
    {
      "name": "channel-name",
      "channelType": "QUEUE",
      "routingKeys": ["key1", "key2"],
      "consumptionType": "STANDARD"
    }
  ],
  "producers": [
    {
      "name": "producer-name",
      "channelName": "channel-name"
    }
  ],
  "channelLinks": [
    {
      "sourceChannelName": "source",
      "targetChannelName": "target",
      "sourceRoutingKey": "key1",
      "targetRoutingKey": "key2"
    }
  ]
}
```

